import React from 'react';
import { Carousel } from 'antd';

const contentStyle = {
  color: '#fff',
  textAlign: 'center',
  background: '#364d79',
  position: 'relative',
};

const textOverlayStyle = {
  position: 'absolute',
  top: '50%', // Center the text vertically
  left: '50%', // Center the text horizontally
  transform: 'translate(-50%, -50%)', // Move the text back by 50% of its width and height
  zIndex: 1, // Ensure the text appears above the image
};

const imageStyle = {
  maxWidth: '100%', // Ensure the image takes the full width of its container
  maxHeight: '100%', // Limit the maximum height of the image
  width: 'auto', // Allow the width to adjust according to the aspect ratio
};

const HomeCarousel = () => (
  <Carousel autoplay style={{ margin: '40px' }}>
    <div style={{ ...contentStyle, height: '500px' }}>
      <h3 style={textOverlayStyle}>
        <div className='font-extrabold'>
          WELCOME SHOP NOW
        </div>
      </h3>
      <img src="/carousel1.avif" alt="Carousel 1" style={imageStyle} />
    </div>
    <div style={{ ...contentStyle, height: '500px' }}>
      <h3 style={textOverlayStyle}>
        <div className='font-extrabold'>
          WELCOME SHOP NOW
        </div>
      </h3>
      <img src="/carousel2.avif" alt="Carousel 2" style={imageStyle} />
    </div>
    <div style={{ ...contentStyle, height: '500px' }}>
      <h3 style={textOverlayStyle}></h3>
      <img src="/carousel3.avif" alt="Carousel 3" style={imageStyle} />
    </div>
    <div style={{ ...contentStyle, height: '500px' }}>
      <h3 style={textOverlayStyle}></h3>
      <img src="/carousel4.avif" alt="Carousel 4" style={imageStyle} />
    </div>
  </Carousel>
);

export default HomeCarousel;
